, "content": "import { chromium, Browser, Page } from '@playwright/test';
import { TestAction, TestScenario, ActionResult, TestResult } from './types';

export class PlaywrightExecutor {
  private browser: Browser | null = null;
  private page: Page | null = null;

  async initialize() {
    this.browser = await chromium.launch();
  }

  async close() {
    await this.browser?.close();
  }

  async executeScenario(scenario: TestScenario, version: 'as-is' | 'to-be'): Promise<TestResult> {
    const startTime = Date.now();
    const results: ActionResult[] = [];
    const screenshots: string[] = [];

    try {
      this.page = await this.browser!.newPage();

      for (const action of scenario.actions) {
        const actionResult = await this.executeAction(action, screenshots);
        results.push(actionResult);

        if (actionResult.status === 'error') {
          break;
        }
      }

      return {
        scenarioId: scenario.id,
        scenarioName: scenario.name,
        version,
        status: results.some((r) => r.status === 'error') ? 'error' : 'passed',
        executionTime: Date.now() - startTime,
        results,
        screenshots,
        executedAt: new Date().toISOString(),
      };
    } catch (error) {
      return {
        scenarioId: scenario.id,
        scenarioName: scenario.name,
        version,
        status: 'error',
        executionTime: Date.now() - startTime,
        results,
        screenshots,
        error: error instanceof Error ? error.message : 'Unknown error',
        executedAt: new Date().toISOString(),
      };
    } finally {
      await this.page?.close();
    }
  }

  private async executeAction(action: TestAction, screenshots: string[]): Promise<ActionResult> {
    try {
      let output: any;

      switch (action.type) {
        case 'navigate':
          await this.page!.goto(action.url!);
          output = `Navigated to ${action.url}`;
          break;

        case 'click':
          await this.page!.click(action.selector!);
          output = `Clicked element: ${action.selector}`;
          break;

        case 'fill':
          await this.page!.fill(action.selector!, action.text!);
          output = `Filled ${action.selector} with text`;
          break;

        case 'select':
          await this.page!.selectOption(action.selector!, action.text!);
          output = `Selected option: ${action.text}`;
          break;

        case 'screenshot':
          const screenshot = await this.page!.screenshot({ fullPage: true });
          const base64 = screenshot.toString('base64');
          screenshots.push(base64);
          output = `Screenshot captured`;
          break;

        case 'wait':
          await this.page!.waitForTimeout(action.milliseconds || 1000);
          output = `Waited ${action.milliseconds}ms`;
          break;

        case 'evaluate':
          output = await this.page!.evaluate((script) => eval(script), action.script!);
          break;

        default:
          throw new Error(`Unknown action type: ${action.type}`);
      }

      return {
        action,
        status: 'passed',
        output,
      };
    } catch (error) {
      return {
        action,
        status: 'error',
        error: error instanceof Error ? error.message : 'Unknown error',
      };
    }
  }
}

export async function executeTest(
  scenario: TestScenario,
  version: 'as-is' | 'to-be'
): Promise<TestResult> {
  const executor = new PlaywrightExecutor();

  try {
    await executor.initialize();
    return await executor.executeScenario(scenario, version);
  } finally {
    await executor.close();
  }
}
