export class ComparisonEngine {
  compareResults(asIsResult: TestResult, toBeResult: TestResult): ComparisonResult {
    const differences = this.findDifferences(asIsResult, toBeResult);
    const status = differences.length === 0 && asIsResult.status === toBeResult.status
      ? 'identical'
      : 'different';

    return {
      scenarioId: asIsResult.scenarioId,
      scenarioName: asIsResult.scenarioName,
      status,
      asIsResult,
      toBeResult,
      differences,
      comparisonReport: this.generateReport(asIsResult, toBeResult, differences),
      comparedAt: new Date().toISOString(),
    };
  }

