function deepEqual(left: unknown, right: unknown): boolean {
  if (left === right) {
    return true;
  }

  if (left == null || right == null) {
    return left === right;
  }

  if (typeof left !== typeof right) {
    return false;
  }

  if (typeof left !== "object" || typeof right !== "object") {
    return left === right;
  }

  const leftKeys = Object.keys(left);
  const rightKeys = Object.keys(right);

  if (leftKeys.length !== rightKeys.length) {
    return false;
  }

  return leftKeys.every((key) =>
    deepEqual((left as Record<string, unknown>)[key], (right as Record<string, unknown>)[key])
  );
}

function compareTestCase(snapshot: TestCaseResult, current: TestCaseResult): TestCaseDiff {
  const stepDiffs: StepDiff[] = [];
  const maxLength = Math.max(snapshot.stepResults.length, current.stepResults.length);

  for (let index = 0; index < maxLength; index += 1) {
    const snapshotStep: StepResult | undefined = snapshot.stepResults[index];
    const currentStep: StepResult | undefined = current.stepResults[index];
    const snapshotOutput = snapshotStep?.output ?? null;
    const currentOutput = currentStep?.output ?? null;
    const isDifferent = !deepEqual(snapshotOutput, currentOutput);

    if (isDifferent || snapshotStep?.status !== currentStep?.status) {
      stepDiffs.push({
        stepIndex: index,
        description: snapshotStep?.step.description ?? currentStep?.step.description,
        snapshotOutput,
        currentOutput,
        isDifferent,
        severity:
          snapshotStep?.status === "error" || currentStep?.status === "error"
            ? "critical"
            : "warning",
      });
    }
  }

  return {
    testCaseId: snapshot.testCaseId,
    testCaseName: snapshot.testCaseName,
    status: stepDiffs.length === 0 ? "identical" : "different",
    stepDiffs,
  };
}

export function compareWithSnapshot(
  snapshot: ScenarioResult,
  current: ScenarioResult
): ComparisonReport {
  const testCaseDiffs = snapshot.testCaseResults.map((snapshotCase) => {
    const currentCase = current.testCaseResults.find(
      (candidate) => candidate.testCaseId === snapshotCase.testCaseId
    );

    if (!currentCase) {
      return {
        testCaseId: snapshotCase.testCaseId,
        testCaseName: snapshotCase.testCaseName,
        status: "error",
        stepDiffs: [],
      } satisfies TestCaseDiff;
    }

    return compareTestCase(snapshotCase, currentCase);
  });

  const hasDifferences = testCaseDiffs.some((diff) => diff.status !== "identical");

  return {
    scenarioId: snapshot.scenarioId,
    snapshotCapturedAt: snapshot.executedAt,
    comparedAt: new Date().toISOString(),
    status: hasDifferences ? "different" : "identical",
    testCaseDiffs,
  };
}
