function resolveLocator(page: Page, locator?: StepLocator, legacySelector?: string): Locator {
  const normalized = normalizeLocator(locator, legacySelector);

  if (!normalized) {
    throw new Error("Locator information is required for this step");
  }

  if (normalized.role) {
    return normalized.name
      ? page.getByRole(normalized.role as Parameters<Page["getByRole"]>[0], {
          name: normalized.name,
        })
      : page.getByRole(normalized.role as Parameters<Page["getByRole"]>[0]);
  }

  if (normalized.label) {
    return page.getByLabel(normalized.label);
  }

  if (normalized.placeholder) {
    return page.getByPlaceholder(normalized.placeholder);
  }

  if (normalized.text) {
    return page.getByText(normalized.text);
  }

  if (normalized.testId) {
    return page.getByTestId(normalized.testId);
  }

  if (normalized.selector) {
    return page.locator(normalized.selector);
  }

  throw new Error("Unable to resolve locator");
}

function describeLocator(locator?: StepLocator, legacySelector?: string): string {
  const normalized = normalizeLocator(locator, legacySelector);

  if (!normalized) {
    return "locator �뾾�쓬";
  }

  if (normalized.role) {
    return normalized.name
      ? `role=${normalized.role}, name=${normalized.name}`
      : `role=${normalized.role}`;
  }

  if (normalized.label) {
    return `label=${normalized.label}`;
  }

  if (normalized.placeholder) {
    return `placeholder=${normalized.placeholder}`;
  }

  if (normalized.text) {
    return `text=${normalized.text}`;
  }

  if (normalized.testId) {
    return `testId=${normalized.testId}`;
  }

  return `legacy selector=${normalized.selector}`;
}

