function trimOrUndefined(value: unknown): string | undefined {
  if (typeof value !== "string") {
    return undefined;
  }

  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : undefined;
}

export function normalizeLocator(
  locator?: StepLocator,
  legacySelector?: string
): StepLocator | undefined {
  const entries = [
    ["role", trimOrUndefined(locator?.role)],
    ["name", trimOrUndefined(locator?.name)],
    ["label", trimOrUndefined(locator?.label)],
    ["placeholder", trimOrUndefined(locator?.placeholder)],
    ["text", trimOrUndefined(locator?.text)],
    ["testId", trimOrUndefined(locator?.testId)],
    ["selector", trimOrUndefined(locator?.selector) ?? trimOrUndefined(legacySelector)],
  ].filter((entry): entry is [keyof StepLocator, string] => entry[1] !== undefined);

  if (entries.length === 0) {
    return undefined;
  }

  return Object.fromEntries(entries) as StepLocator;
}

export function getLocatorSummary(locator?: StepLocator, legacySelector?: string): string {
  const normalized = normalizeLocator(locator, legacySelector);

